script:
#!/usr/bin/env bash
set -euo pipefail
I=$(head -c 65536)
jq -e . >/dev/null 2>&1 <<<"$I" || { echo '{"decision":"approve"}'; exit 0; }
CMD=$(jq -r '.tool_input.command // ""' <<<"$I")
[[ "$CMD" != cd\ * ]] && { echo '{"decision":"approve"}'; exit 0; }
TARGET=$(echo "$CMD" | sed 's/^cd *//' | awk '{print $1}')
[ -z "$TARGET" ] && { echo '{"decision":"approve"}'; exit 0; }
if [ -f "$TARGET/.envrc" ]; then
  direnv allow "$TARGET" >/dev/null 2>&1 || true
  printf 'direnv will reload %s/.envrc\n' "$TARGET" >&2
fi
echo '{"decision":"approve"}'
